import React, { useState, useEffect, useMemo, useCallback, useRef } from 'react';
import { Container, Card, Stack, Row, Box, Divider, Spacer, Text, Heading, Button, Input, TextArea, Select, Checkbox, Toggle, RadioGroup, Slider, Badge, Spinner, Avatar, Alert, Progress, Image, Icon, Link, Tooltip, Table, Tabs, Toast, Accordion } from '@ggui-ai/design/primitives';
import { SearchField, FormField, MenuItem, Tag, Dropdown, Autocomplete, Breadcrumb, Pagination } from '@ggui-ai/design/components';
import { Header, Sidebar, CardGrid, CommentThread, DataTable, ChatWindow, NavigationBar, FileUploader, UserProfileCard, NotificationCenter, Modal, CommandPalette, Footer, Hero } from '@ggui-ai/design/compositions';
import { Clickable, Hoverable, Pressable } from '@ggui-ai/design/interact';

// ⚠️ DO NOT EDIT — generated from data contract. Changing this will fail validation.
interface Props {
  city: string; // City name
  temperature: number; // Current temperature
  condition: string; // Weather condition (Sunny, Cloudy, Rainy, etc.)
  humidity: number; // Humidity percentage
  windSpeed: number; // Wind speed
  unit: string; // Temperature unit (C or F)
  forecast: Array<{ day?: string; icon?: string; high?: number; low?: number }>; // 5-day forecast array
}

function useComponent(props: Props) {
  const conditionIcon = useMemo(() => {
    const cond = props.condition.toLowerCase();
    if (cond.includes('sun')) return 'sun';
    if (cond.includes('rain')) return 'cloud-rain';
    if (cond.includes('cloud')) return 'cloud';
    return 'sun';
  }, [props.condition]);

  return { conditionIcon };
}

export default function Component(props: Props) {
  const { conditionIcon } = useComponent(props);

  return (
    <Card shadow="md" padding={24} radius="lg" style={{ maxWidth: '400px' }}>
      <Stack gap={16}>
        <Row justify="between" align="center">
          <Heading level={2}>{props.city}</Heading>
          <Badge variant="primary">{props.condition}</Badge>
        </Row>
        <Stack align="center" gap={4}>
          <Icon name={conditionIcon} size={64} color="var(--ggui-color-primary-600)" />
          <Heading level={1}>{props.temperature}°{props.unit}</Heading>
        </Stack>
        <Row justify="center" gap={32}>
          <Stack align="center" gap={4}>
            <Text variant="caption" color="var(--ggui-color-onSurfaceVariant)">Humidity</Text>
            <Text variant="label">{props.humidity}%</Text>
          </Stack>
          <Stack align="center" gap={4}>
            <Text variant="caption" color="var(--ggui-color-onSurfaceVariant)">Wind</Text>
            <Text variant="label">{props.windSpeed} mph</Text>
          </Stack>
        </Row>
        <Divider margin={8} />
        <Row justify="between" style={{ padding: 'var(--ggui-spacing-2, 8px) 0' }}>
          {props.forecast.map((day, idx) => (
            <Box as={Hoverable} key={idx} style={{ transition: 'transform 200ms ease' }} hoverStyle={{ transform: 'translateY(-4px)' }}>
              <Stack align="center" gap={8} style={{ padding: 'var(--ggui-spacing-2, 8px)' }}>
                <Text variant="caption">{day.day}</Text>
                <Icon name={day.icon || 'sun'} size={24} color="var(--ggui-color-primary-500)" />
                <Text variant="bodySmall" weight="bold">{day.high}° / {day.low}°</Text>
              </Stack>
            </Box>
          ))}
        </Row>
      </Stack>
    </Card>
  );
}

// ⚠️ DO NOT EDIT imports — all available components are pre-imported.
import React, { useState, useEffect, useMemo, useCallback, useRef } from 'react';
import { Container, Card, Stack, Row, Box, Divider, Spacer, Text, Heading, Button, Input, TextArea, Select, Checkbox, Toggle, RadioGroup, Slider, Badge, Spinner, Avatar, Alert, Progress, Image, Icon, Link, Tooltip, Table, Tabs, Toast, Accordion } from '@ggui-ai/design/primitives';
import { SearchField, FormField, MenuItem, Tag, Dropdown, Autocomplete, Breadcrumb, Pagination } from '@ggui-ai/design/components';
import { Header, Sidebar, CardGrid, CommentThread, DataTable, ChatWindow, NavigationBar, FileUploader, UserProfileCard, NotificationCenter, Modal, CommandPalette, Footer, Hero } from '@ggui-ai/design/compositions';
import { Clickable, Hoverable, Pressable } from '@ggui-ai/design/interact';

// ⚠️ DO NOT EDIT — generated from data contract. Changing this will fail validation.
interface Props {
  tasks: Array<{ id?: string; title?: string; priority?: 'low' | 'medium' | 'high'; assignee?: string; column?: string; dueDate?: string }>; // Array of tasks with id, title, priority (low/medium/high), assignee initials, column ID, and optional dueDate
  columns: Array<{ id?: string; name?: string }>;
  onTaskUpdate?: (data: Record<string, unknown>) => void; // Action: Task Updated
}

function useComponent(props: Props) {
  const handleTaskUpdate = useCallback((data: Record<string, unknown>) => {
    props.onTaskUpdate?.(data);
  }, [props.onTaskUpdate]);

  const [tasks, setTasks] = useState(props.tasks || []);
  const [addingTask, setAddingTask] = useState<string | null>(null);
  const [newTaskTitle, setNewTaskTitle] = useState('');
  const [newTaskPriority, setNewTaskPriority] = useState<'low' | 'medium' | 'high'>('medium');
  const [newTaskDueDate, setNewTaskDueDate] = useState('');
  const [editingTaskId, setEditingTaskId] = useState<string | null>(null);

  const totalTasks = tasks.length;
  const completedTasks = tasks.filter(t => t.column === 'done').length;

  const moveTask = (taskId: string, columnId: string) => {
    const updatedTasks = tasks.map(t => t.id === taskId ? { ...t, column: columnId } : t);
    setTasks(updatedTasks);
    handleTaskUpdate({ type: 'MOVE_TASK', taskId, columnId });
  };

  const updateTask = (taskId: string, newTitle: string) => {
    const updatedTasks = tasks.map(t => t.id === taskId ? { ...t, title: newTitle } : t);
    setTasks(updatedTasks);
    handleTaskUpdate({ type: 'UPDATE_TASK', taskId, title: newTitle });
  };

  const addTask = (columnId: string) => {
    if (!newTaskTitle.trim()) return;
    const newTask = {
      id: Date.now().toString(),
      title: newTaskTitle,
      priority: newTaskPriority,
      column: columnId,
      assignee: '??',
      dueDate: newTaskDueDate
    };
    setTasks([...tasks, newTask]);
    setNewTaskTitle('');
    setNewTaskDueDate('');
    setAddingTask(null);
    handleTaskUpdate({ type: 'ADD_TASK', task: newTask });
  };

  return { tasks, columns: props.columns, totalTasks, completedTasks, addingTask, setAddingTask, newTaskTitle, setNewTaskTitle, newTaskPriority, setNewTaskPriority, newTaskDueDate, setNewTaskDueDate, moveTask, addTask, editingTaskId, setEditingTaskId, updateTask };
}

export default function Component(props: Props) {
  const { tasks, columns, totalTasks, completedTasks, addingTask, setAddingTask, newTaskTitle, setNewTaskTitle, newTaskPriority, setNewTaskPriority, newTaskDueDate, setNewTaskDueDate, moveTask, addTask, editingTaskId, setEditingTaskId, updateTask } = useComponent(props);

  return (
    <Container maxWidth="3xl" padding={24}>
      <Stack gap={24}>
        <Row justify="between" align="center">
          <Heading level={1}>Kanban Board</Heading>
          <Row gap={16}>
            <Badge variant="primary" size="lg">{totalTasks} Total</Badge>
            <Badge variant="success" size="lg">{completedTasks} Completed</Badge>
          </Row>
        </Row>

        <Row gap={24} align="start" wrap>
          {columns.map(col => (
            <Box key={col.id} background="var(--ggui-color-surfaceVariant, #f4f4f5)" padding={16} borderRadius="lg" style={{ flex: 1, minWidth: 320 }}>
              <Stack gap={16}>
                <Row justify="between" align="center">
                  <Heading level={4}>{col.name}</Heading>
                  <Badge variant="secondary">{tasks.filter(t => t.column === col.id).length}</Badge>
                </Row>
                <Stack gap={12}>
                {tasks.filter(t => t.column === col.id).map(task => (
                  <Card key={task.id} padding={16} radius="md" shadow="sm" border={true}>
                    <Stack gap={8}>
                      {editingTaskId === task.id ? (
                        <Input autoFocus value={task.title} onChange={(val) => updateTask(task.id!, val)} onBlur={() => setEditingTaskId(null)} placeholder="Enter task title..." />
                      ) : (
                        <Box as={Clickable} onClick={() => setEditingTaskId(task.id!)}>
                          <Row justify="between" align="start" gap={8}>
                            <Text variant="body" style={{ fontWeight: 'var(--ggui-font-weight-medium)' }}>{task.title}</Text>
                            <Avatar name={task.assignee || '??'} size={24} shape="circle" />
                          </Row>
                        </Box>
                      )}
                      <Row justify="between" align="center" gap={8}>
                        <Badge variant={task.priority === 'high' ? 'error' : task.priority === 'medium' ? 'warning' : 'primary'} size="sm" pill>{task.priority}</Badge>
                        {task.dueDate && <Text variant="caption" color="var(--ggui-color-onSurfaceVariant)">{new Date(task.dueDate).toLocaleDateString()}</Text>}
                      </Row>
                      <Divider margin={4} />
                      <Row justify="between" align="center">
                        <Text variant="caption" color="var(--ggui-color-onSurfaceVariant)">Move to:</Text>
                        <Dropdown
                          trigger={<Button variant="ghost" size="xs" rightIcon={<Icon name="chevron-down" size={12} />}>Select</Button>}
                          options={columns.map(c => ({ value: c.id!, label: c.name! }))}
                          value={task.column}
                          onChange={(newColId) => moveTask(task.id!, newColId)}
                          placement="bottom-end"
                        />
                      </Row>
                    </Stack>
                  </Card>
                ))}
              </Stack>
              {addingTask === col.id ? (
                <Card padding={16} radius="md" shadow="md" background="var(--ggui-color-surface, #ffffff)">
                  <Stack gap={12}>
                    <FormField label="Title"><Input value={newTaskTitle} onChange={setNewTaskTitle} placeholder="e.g., UI Polish" autoFocus /></FormField>
                    <FormField label="Priority"><Select value={newTaskPriority} onChange={(v) => setNewTaskPriority(v as any)} options={[{value:'low', label:'Low'}, {value:'medium', label:'Medium'}, {value:'high', label:'High'}]} /></FormField>
                    <FormField label="Due"><Input type="date" value={newTaskDueDate} onChange={setNewTaskDueDate} /></FormField>
                    <Row gap={8}>
                      <Button variant="primary" size="sm" onClick={() => addTask(col.id)}>Add Task</Button>
                      <Button variant="ghost" size="sm" onClick={() => setAddingTask(null)}>Cancel</Button>
                    </Row>
                  </Stack>
                </Card>
              ) : (
                <Button variant="ghost" size="md" onClick={() => setAddingTask(col.id)} leftIcon={<Icon name="plus" size={16}/>}>Add Task</Button>
              )}
              </Stack>
            </Box>
          ))}
        </Row>
      </Stack>
    </Container>
  );
}

