import React, { useState, useEffect, useMemo, useCallback, useRef } from 'react';
import { Container, Card, Stack, Row, Box, Divider, Spacer, Text, Heading, Button, Input, TextArea, Select, Checkbox, Toggle, RadioGroup, Slider, Badge, Spinner, Avatar, Alert, Progress, Image, Icon, Link, Tooltip, Table, Tabs, Toast, Accordion } from '@ggui-ai/design/primitives';
import { SearchField, FormField, MenuItem, Tag, Dropdown, Autocomplete, Breadcrumb, Pagination } from '@ggui-ai/design/components';
import { Header, Sidebar, CardGrid, CommentThread, DataTable, ChatWindow, NavigationBar, FileUploader, UserProfileCard, NotificationCenter, Modal, CommandPalette, Footer, Hero } from '@ggui-ai/design/compositions';
import { Clickable, Hoverable, Pressable } from '@ggui-ai/design/interact';

// ⚠️ DO NOT EDIT — generated from data contract. Changing this will fail validation.
interface Props {
  elements: Array<{ atomicNumber?: number; symbol?: string; name?: string; atomicWeight?: number; category?: string; row?: number; col?: number }>; // Full periodic table element data
}

function useComponent(props: Props) {
  const [search, setSearch] = useState('');
  const [selected, setSelected] = useState<Props['elements'][0] | null>(null);

  const categories = useMemo(() => Array.from(new Set(props.elements.map(e => e.category || 'Unknown'))), [props.elements]);

  const categoryColors: Record<string, string> = useMemo(() => {
    const colors = ['var(--ggui-color-error-400, #f87171)', 'var(--ggui-color-warning-400, #fb923c)', 'var(--ggui-color-warning-500, #fbbf24)', 'var(--ggui-color-warning-600, #facc15)', 'var(--ggui-color-success-400, #a3e635)', 'var(--ggui-color-success-500, #4ade80)', 'var(--ggui-color-info-400, #22d3ee)', 'var(--ggui-color-primary-400, #818cf8)', 'var(--ggui-color-container, #c084fc)', 'var(--ggui-color-primary-200, #f472b6)'];
    return categories.reduce((acc, cat, i) => ({ ...acc, [cat]: colors[i % colors.length] }), {});
  }, [categories]);

  const filtered = useMemo(() => 
    props.elements.filter(e => 
      e.name?.toLowerCase().includes(search.toLowerCase()) || 
      e.symbol?.toLowerCase().includes(search.toLowerCase())
    ), [props.elements, search]);

  return { search, setSearch, selected, setSelected, filtered, categoryColors, categories };
}

export default function Component(props: Props) {
  const { search, setSearch, selected, setSelected, filtered, categoryColors, categories } = useComponent(props);

  return (
    <Container maxWidth="3xl" padding={24}>
      <Stack gap={24}>
        <Heading level={1} align="center">Periodic Table of Elements</Heading>
        <SearchField value={search} onChange={setSearch} placeholder="Search by name or symbol..." />

        <Box style={{ display: 'grid', gridTemplateColumns: 'repeat(18, 1fr)', gap: '4px' }}>
          {props.elements.map((el) => (
            <Card 
              key={el.symbol} 
              as={Clickable}
              aria-label={`Element: ${el.name || 'Unknown'}, Symbol: ${el.symbol}, Atomic Number: ${el.atomicNumber}`}
              onClick={() => setSelected(el)}
              style={{ 
                gridColumn: el.col || 'auto', 
                gridRow: el.row || 'auto', 
                aspectRatio: '1/1',
                opacity: filtered.includes(el) ? 1 : 0.2,
                backgroundColor: categoryColors[el.category || 'Unknown'],
                transition: 'all 0.2s ease',
                border: '1px solid rgba(0,0,0,0.1)',
                display: 'flex',
                flexDirection: 'column',
                justifyContent: 'center',
                alignItems: 'center',
                padding: 'var(--ggui-spacing-1)'
              }}
            >
              <Text variant="caption" style={{ fontSize: '10px', fontWeight: 600, color: 'rgba(0,0,0,0.5)' }}>{el.atomicNumber}</Text>
              <Heading level={6} style={{ margin: 0, fontWeight: 700, color: 'rgba(0,0,0,0.8)' }}>{el.symbol}</Heading>
            </Card>
          ))}
        </Box>

        <Row justify="center" gap={12} wrap>
          {categories.map(cat => (
            <Badge key={cat} variant="default" style={{ backgroundColor: categoryColors[cat], color: '#000', padding: '4px 8px' }}>{cat}</Badge>
          ))}
        </Row>

        <Modal open={!!selected} onClose={() => setSelected(null)} title="Element Details">
          {selected && (
            <Stack gap={16}>
              <Row justify="between">
                <Heading level={3}>{selected.name}</Heading>
                <Badge variant="primary" style={{ backgroundColor: categoryColors[selected.category || 'Unknown'], color: '#000', padding: '4px 8px' }}>{selected.category}</Badge>
              </Row>
              <Divider />
              <Stack gap={8}>
                <Text variant="label">Symbol: <Text as="span" variant="body">{selected.symbol}</Text></Text>
                <Text variant="label">Atomic Number: <Text as="span" variant="body">{selected.atomicNumber}</Text></Text>
                <Text variant="label">Atomic Weight: <Text as="span" variant="body">{selected.atomicWeight}</Text></Text>
              </Stack>
              <Button variant="secondary" onClick={() => setSelected(null)}>Close</Button>
            </Stack>
          )}
        </Modal>
      </Stack>
    </Container>
  );
}

