import React, { useState, useEffect, useMemo, useCallback, useRef } from 'react';
import { Container, Card, Stack, Row, Box, Divider, Spacer, Text, Heading, Button, Input, TextArea, Select, Checkbox, Toggle, RadioGroup, Slider, Badge, Spinner, Avatar, Alert, Progress, Image, Icon, Link, Tooltip, Table, Tabs, Toast, Accordion } from '@ggui-ai/design/primitives';
import { SearchField, FormField, MenuItem, Tag, Dropdown, Autocomplete, Breadcrumb, Pagination } from '@ggui-ai/design/components';
import { Header, Sidebar, CardGrid, CommentThread, DataTable, ChatWindow, NavigationBar, FileUploader, UserProfileCard, NotificationCenter, Modal, CommandPalette, Footer, Hero } from '@ggui-ai/design/compositions';
import { Clickable, Hoverable, Pressable } from '@ggui-ai/design/interact';

// ⚠️ DO NOT EDIT — generated from data contract. Changing this will fail validation.
interface Props {
  product: { id?: string; name?: string; price?: number; currency?: string; rating?: number; reviewCount?: number; stock?: number; description?: string; specifications?: unknown[]; reviews?: unknown[] }; // Product object with id, name, price, currency, rating, stock, description, specifications[], reviews[]
  onAddToCart?: (data: Record<string, unknown>) => void; // Action: Add to Cart
}

function useComponent(props: Props) {
  const handleAddToCart = useCallback((data: Record<string, unknown>) => {
    props.onAddToCart?.(data);
  }, [props.onAddToCart]);

  const [quantity, setQuantity] = useState(1);
  const [activeTab, setActiveTab] = useState('description');

  const handleQuantityChange = useCallback((newQty: number) => {
    const clamped = Math.max(1, Math.min(newQty, props.product.stock || 0));
    setQuantity(clamped);
  }, [props.product.stock]);

  const isOutOfStock = (props.product.stock || 0) === 0;

  return { quantity, activeTab, setActiveTab, handleQuantityChange, handleAddToCart, isOutOfStock };
}

export default function Component(props: Props) {
  const { quantity, activeTab, setActiveTab, handleQuantityChange, handleAddToCart, isOutOfStock } = useComponent(props);
  const { product } = props;

  return (
    <Container maxWidth="lg" padding={24}>
      <Stack gap={32}>
        <Stack direction="horizontal" gap={32} align="start" wrap={true}>
          <Box background="var(--ggui-color-surfaceVariant)" padding={48} borderRadius="lg" style={{ flex: '1 1 400px', minHeight: '300px', display: 'flex', justifyContent: 'center', alignItems: 'center' }}>
            <Heading level={2} color="var(--ggui-color-onSurfaceVariant)">{product.name}</Heading>
          </Box>

          <Stack gap={16} style={{ flex: '1 1 300px' }}>
            <Heading level={1}>{product.name}</Heading>
            <Text variant="bodyLarge" weight="bold" color="var(--ggui-color-onSurface)">{product.currency ?? '$'}{product.price?.toFixed(2)}</Text>
            <Row gap={4}>
              {Array.from({ length: 5 }).map((_, i) => (
                <Icon key={i} name="star" size={16} color={i < Math.round(product.rating || 0) ? 'var(--ggui-color-warning-500, #f59e0b)' : 'var(--ggui-color-outline, #d4d4d8)'} />
              ))}
              <Text variant="bodySmall" color="var(--ggui-color-onSurfaceVariant)">({product.reviewCount} reviews)</Text>
            </Row>
            <Box>
              <Badge variant={(product.stock || 0) > 5 ? 'success' : (product.stock || 0) > 0 ? 'warning' : 'error'}>
                {(product.stock || 0) > 5 ? 'In Stock' : (product.stock || 0) > 0 ? 'Low Stock' : 'Out of Stock'}
              </Badge>
            </Box>

            <Row gap={8} align="center" style={{ marginTop: 'var(--ggui-spacing-2)' }}>
              <Button variant="outline" size="sm" aria-label="Decrease quantity" onClick={() => handleQuantityChange(quantity - 1)}><Icon name="minus" size={14} /></Button>
              <Text style={{ minWidth: '40px', textAlign: 'center' }} aria-label={`Quantity: ${quantity}`}>{quantity}</Text>
              <Button variant="outline" size="sm" aria-label="Increase quantity" onClick={() => handleQuantityChange(quantity + 1)}><Icon name="plus" size={14} /></Button>
            </Row>
            <Button variant="primary" size="lg" disabled={isOutOfStock} onClick={() => handleAddToCart({ productId: product.id || '', quantity })}>
              {isOutOfStock ? 'Out of Stock' : 'Add to Cart'}
            </Button>
          </Stack>
        </Stack>

        <Tabs 
          variant="line" 
          activeKey={activeTab} 
          onChange={setActiveTab}
          items={[
            { key: 'description', label: 'Description', content: <Box paddingY={16}><Text>{product.description}</Text></Box> },
            { key: 'specs', label: 'Specifications', content: <Box paddingY={16}><Table data={(product.specifications || []) as any[]} columns={[{ key: 'name', header: 'Name' }, { key: 'value', header: 'Value' }]} /></Box> },
            { key: 'reviews', label: 'Reviews', content: <Stack gap={16}>
              {(product.reviews as any[] || []).map((r, i) => (
                <Card key={i} padding={16} shadow="none" border={true} radius="md">
                  <Stack gap={4}>
                    <Row justify="between">
                      <Text weight="semibold">{r.author}</Text>
                      <Text variant="caption" color="var(--ggui-color-onSurfaceVariant)">{new Date(r.date).toLocaleDateString()}</Text>
                    </Row>
                    <Row gap={2}>
                      {Array.from({ length: 5 }).map((_, j) => <Icon key={j} name="star" size={12} color={j < r.rating ? 'var(--ggui-color-warning-500, #f59e0b)' : 'var(--ggui-color-outline, #d4d4d8)'} />)}
                    </Row>
                    <Text variant="bodySmall">{r.text}</Text>
                  </Stack>
                </Card>
              ))}
            </Stack> }
          ]}
        />
      </Stack>
    </Container>
  );
}

// ⚠️ DO NOT EDIT imports — all available components are pre-imported.
import React, { useState, useEffect, useMemo, useCallback, useRef } from 'react';
import { Container, Card, Stack, Row, Box, Divider, Spacer, Text, Heading, Button, Input, TextArea, Select, Checkbox, Toggle, RadioGroup, Slider, Badge, Spinner, Avatar, Alert, Progress, Image, Icon, Link, Tooltip, Table, Tabs, Toast, Accordion } from '@ggui-ai/design/primitives';
import { SearchField, FormField, MenuItem, Tag, Dropdown, Autocomplete, Breadcrumb, Pagination } from '@ggui-ai/design/components';
import { Header, Sidebar, CardGrid, CommentThread, DataTable, ChatWindow, NavigationBar, FileUploader, UserProfileCard, NotificationCenter, Modal, CommandPalette, Footer, Hero } from '@ggui-ai/design/compositions';
import { Clickable, Hoverable, Pressable } from '@ggui-ai/design/interact';

// ⚠️ DO NOT EDIT — generated from data contract. Changing this will fail validation.
interface Props {
  initialProfile: { name?: string; email?: string; avatar?: string; role?: string; emailNotifications?: boolean; theme?: string }; // Pre-filled profile data for editing (all fields optional)
  avatarOptions: string[]; // Available avatar emojis to choose from
  roleOptions: string[]; // Available role options for the dropdown
  onComplete?: (data: Record<string, unknown>) => void; // Action: Complete Setup
}

function useComponent(props: Props) {
  const [activeStep, setActiveStep] = useState(1);
  const [formData, setFormData] = useState({
    name: props.initialProfile.name || '',
    email: props.initialProfile.email || '',
    avatar: props.initialProfile.avatar || props.avatarOptions[0] || '',
    role: props.initialProfile.role || '',
    emailNotifications: props.initialProfile.emailNotifications ?? true,
    theme: props.initialProfile.theme || 'light',
  });

  const isStepValid = useMemo(() => {
    if (activeStep === 1) return formData.name.trim() !== '' && /^[^\s@]+@[^\s@]+\.[^\s@]+$/.test(formData.email);
    if (activeStep === 2) return formData.role !== '' && formData.role !== undefined;
    return true;
  }, [activeStep, formData]);

  const handleNext = useCallback(() => setActiveStep((s) => Math.min(s + 1, 3)), []);
  const handleBack = useCallback(() => setActiveStep((s) => Math.max(s - 1, 1)), []);
  const handleComplete = useCallback(() => props.onComplete?.(formData as unknown as Record<string, unknown>), [props.onComplete, formData]);

  return { activeStep, formData, setFormData, isStepValid, handleNext, handleBack, handleComplete };
}

export default function Component(props: Props) {
  const { activeStep, formData, setFormData, isStepValid, handleNext, handleBack, handleComplete } = useComponent(props);

  return (
    <Container maxWidth="sm" padding={24}>
      <Stack gap={16}>
        <div style={{ animation: 'ggui-fadeIn 300ms ease-in-out' }}>
          <Stack gap={4}>
            <Text variant="label">Step {activeStep} of 3</Text>
            <Progress value={(activeStep / 3) * 100} size="md" variant="primary" />
          </Stack>
        </div>

        <Box style={{ transition: 'opacity 200ms ease-in-out', opacity: 1 }}>
          <Card padding={24} shadow="md">
            {activeStep === 1 && (
            <Stack gap={16}>
              <Heading level={2}>Profile Setup</Heading>
              <FormField label="Name" required><Input placeholder="John Doe" value={formData.name} onChange={(v) => setFormData({...formData, name: v})} /></FormField>
              <FormField label="Email" required><Input type="email" placeholder="john@example.com" value={formData.email} onChange={(v) => setFormData({...formData, email: v})} /></FormField>
              <Text variant="label">Choose Avatar</Text>
              <Row gap={8}>
                {props.avatarOptions.map(emoji => (
                  <Box as={Clickable} key={emoji} onClick={() => setFormData({...formData, avatar: emoji})} padding={8} background={formData.avatar === emoji ? 'var(--ggui-color-primary-100)' : 'var(--ggui-color-surfaceVariant)'} borderRadius={8}>
                      <Text size="3xl">{emoji}</Text>
                  </Box>
                ))}
              </Row>
            </Stack>
          )}
          {activeStep === 2 && (
            <Stack gap={16}>
              <Heading level={2}>Preferences</Heading>
              <FormField label="Role"><Select value={formData.role} onChange={(v) => setFormData({...formData, role: v})} options={props.roleOptions.map(r => ({value: r, label: r}))} placeholder="Select a role" /></FormField>
              <Toggle label="Email notifications" checked={formData.emailNotifications} onChange={(v) => setFormData({...formData, emailNotifications: v})} />
              <Toggle label="Dark mode" checked={formData.theme === 'dark'} onChange={(v) => setFormData({...formData, theme: v ? 'dark' : 'light'})} />
            </Stack>
          )}
          {activeStep === 3 && (
            <Stack gap={16}>
              <Heading level={2}>Review</Heading>
              <Card variant="outline" padding={16} background="var(--ggui-color-surfaceVariant)">
                <Stack gap={8}>
                  <Row gap={16} align="center">
                    <Text size="4xl">{formData.avatar}</Text>
                    <Heading level={3}>{formData.name}</Heading>
                  </Row>
                  <Divider />
                  <Text variant="body">Email: {formData.email}</Text>
                  <Text variant="body">Role: {formData.role || 'Not set'}</Text>
                </Stack>
              </Card>
            </Stack>
          )}
          </Card>
        </Box>

        <Row justify="between">
          <Button variant="ghost" disabled={activeStep === 1} onClick={handleBack}>Go Back</Button>
          {activeStep < 3 ? (
            <Button variant="primary" disabled={!isStepValid} onClick={handleNext}>Next</Button>
          ) : (
            <Button variant="primary" onClick={() => handleComplete()}>Complete Setup</Button>
          )}
        </Row>
      </Stack>
    </Container>
  );
}
